16	
17	async function executeSearch(
18	  body: Record<string, unknown>,
19	  clerkOrgId: string,
20	  signal: AbortSignal
21	): Promise<SearchResponse> {
22	  const response = await fetch("/v1/search", {
23	    method: "POST",
24	    headers: {
25	      "Content-Type": "application/json",
26	      "X-Org-ID": clerkOrgId,
27	    },
28	    body: JSON.stringify(body),
29	    signal,
30	  });
31	
32	  if (!response.ok) {
33	    const errorData = (await response
34	      .json()
35	      .catch(() => ({ error: undefined, message: undefined }))) as {
36	      error?: string;
37	      message?: string;
38	    };
39	    throw new Error(
40	      errorData.message ??
41	        errorData.error ??
42	        `Search failed: ${response.status}`
43	    );
44	  }
45	
46	  return (await response.json()) as SearchResponse;
47	}
