24	
25	export const useTRPC = trpcContext.useTRPC;
26	export const TRPCProvider = trpcContext.TRPCProvider;
27	
28	const mutationCache = new MutationCache({
29	  onError: (error, _variables, _context, mutation) => {
30	    if (mutation.options.meta?.suppressErrorToast) {
31	      return;
32	    }
33	
34	    const title = mutation.options.meta?.errorTitle ?? "Something went wrong";
35	
36	    let message = "An unexpected error occurred. Please try again.";
37	    if (
38	      error instanceof TRPCClientError &&
39	      error.data?.httpStatus != null &&
40	      error.data.httpStatus < 500
41	    ) {
42	      message = error.message;
43	    }
44	
45	    toast.error(title, { description: message });
46	  },
47	});
48	
49	let clientQueryClientSingleton: QueryClient | undefined;
50	
51	function getQueryClient() {
52	  if (typeof window === "undefined") {
53	    return createQueryClient();
54	  }
55	
56	  return (clientQueryClientSingleton ??= createQueryClient({ mutationCache }));
57	}
58	
59	function defaultGetBaseUrl() {
60	  if (typeof window !== "undefined") {
61	    return window.location.origin;
62	  }
63	  if (process.env.VERCEL_URL) {
64	    return `https://${process.env.VERCEL_URL}`;
65	  }
66	  return `http://localhost:${process.env.PORT ?? 4104}`;
67	}
68	
69	export function TRPCReactProvider({
70	  children,
71	  options,
72	}: {
73	  children: React.ReactNode;
74	  options?: CreateTRPCReactProviderOptions;
75	}) {
76	  const queryClient = getQueryClient();
77	
78	  const [trpcClient] = useState(() => {
79	    const baseUrl = options?.baseUrl ?? defaultGetBaseUrl();
80	
81	    return createTRPCClient<AppRouter>({
82	      links: [
83	        loggerLink({
